head.b:skin:
/*------------------------------------------------------------
PREMIUM GRADIENT COLOR SYSTEM (HadotiEMitra Theme)
------------------------------------------------------------*/
:root {
    --primary-gradient: linear-gradient(135deg, #ff007f 0%, #7928ca 100%);
    --secondary-gradient: linear-gradient(135deg, #00f2fe 0%, #4facfe 100%);
    --accent-color: #ff007f;
    --dark-bg: #090d16;
    --dark-card: #131c2e;
    --light-bg: #f3f4f6;
    --light-card: #ffffff;
    --text-main: #1e293b;
    --text-muted: #64748b;
    --font-premium: 'Plus Jakarta Sans', sans-serif;
    --radius-prm: 16px;
    --shadow-prm: 0 10px 30px -5px rgba(121, 40, 202, 0.15);
    --transition: all 0.4s cubic-bezier(0.16, 1, 0.3, 1);
}

/* Dark Mode Variables Toggle */
body.dark-mode {
    --light-bg: var(--dark-bg);
    --light-card: var(--dark-card);
    --text-main: #f8fafc;
    --text-muted: #94a3b8;
    --shadow-prm: 0 10px 30px -5px rgba(0, 0, 0, 0.5);
}

/* Core Reset */
* { box-sizing: border-box; margin: 0; padding: 0; }
body { font-family: var(--font-premium); background-color: var(--light-bg); color: var(--text-main); transition: var(--transition); overflow-x: hidden; }
a { color: inherit; text-decoration: none; transition: var(--transition); }
img { max-width: 100%; height: auto; display: block; }

/* Reading Progress Bar */
#progress-bar { position: fixed; top: 0; left: 0; width: 0%; height: 4px; background: var(--primary-gradient); z-index: 9999; transition: width 0.1s ease; }

/* Global Layout Container */
.container { max-width: 1240px; margin: 0 auto; padding: 0 24px; }

/* Top Bar & Breaking News (Premium Neon Look) */
.top-bar { background: #0b0f19; color: #fff; padding: 12px 0; font-size: 13px; font-weight: 500; border-bottom: 1px solid rgba(255,255,255,0.05); }
.ticker-wrap { display: flex; align-items: center; justify-content: space-between; gap: 15px; }
.ticker-box { display: flex; align-items: center; overflow: hidden; width: 70%; }
.ticker-title { background: var(--primary-gradient); padding: 6px 14px; font-weight: 700; border-radius: 6px; margin-right: 15px; white-space: nowrap; box-shadow: 0 4px 12px rgba(255, 0, 127, 0.3); font-size: 11px; letter-spacing: 1px; }
.ticker-content { display: inline-block; white-space: nowrap; animation: ticker 30s linear infinite; color: #e2e8f0; }
@keyframes ticker { 0% { transform: translate3d(100%, 0, 0); } 100% { transform: translate3d(-100%, 0, 0); } }

/* Header & Navigation (Blur Glass Effect) */
header { background: rgba(255, 255, 255, 0.8); backdrop-filter: blur(12px); -webkit-backdrop-filter: blur(12px); position: sticky; top: 0; z-index: 1000; box-shadow: 0 4px 20px rgba(0,0,0,0.03); transition: var(--transition); border-bottom: 1px solid rgba(0,0,0,0.05); }
body.dark-mode header { background: rgba(19, 28, 46, 0.8); border-bottom: 1px solid rgba(255,255,255,0.05); }
.header-inner { display: flex; justify-content: space-between; align-items: center; padding: 18px 0; }

/* Premium Logo Style */
.logo h1 { font-size: 26px; font-weight: 800; background: var(--primary-gradient); -webkit-background-clip: text; -webkit-text-fill-color: transparent; letter-spacing: -0.5px; }

/* Modern Nav Menu */
nav ul { display: flex; list-style: none; gap: 28px; }
nav ul li a { font-weight: 600; font-size: 15px; color: var(--text-main); position: relative; padding: 5px 0; }
nav ul li a::after { content: ''; position: absolute; bottom: 0; left: 0; width: 0; height: 2px; background: var(--primary-gradient); transition: var(--transition); }
nav ul li a:hover::after { width: 100%; }

/* Action Buttons */
.nav-actions { display: flex; align-items: center; gap: 20px; }
.action-btn { width: 40px; height: 40px; border-radius: 50%; background: var(--light-bg); display: flex; align-items: center; justify-content: center; cursor: pointer; transition: var(--transition); border: 1px solid rgba(0,0,0,0.05); }
.action-btn:hover { transform: scale(1.1); background: var(--primary-gradient); color: #fff; }

/* Search Popup Box */
.search-overlay { position: fixed; top: 0; left: 0; width: 100%; height: 100%; background: rgba(9, 13, 22, 0.9); z-index: 9999; display: none; align-items: center; justify-content: center; backdrop-filter: blur(8px); }
.search-dialog { background: var(--light-card); padding: 35px; border-radius: var(--radius-prm); width: 90%; max-width: 550px; box-shadow: var(--shadow-prm); border: 1px solid rgba(255,255,255,0.1); }
.search-dialog input { width: 100%; padding: 16px; border: 2px solid rgba(0,0,0,0.05); border-radius: 10px; background: var(--light-bg); color: var(--text-main); font-size: 16px; font-family: var(--font-premium); font-weight: 500; outline: none; transition: var(--transition); }
.search-dialog input:focus { border-color: var(--accent-color); }

/* Hero Gradient Section */
.hero-banner { background: var(--primary-gradient); padding: 50px 0; color: #fff; border-radius: var(--radius-prm); margin-top: 30px; text-align: center; box-shadow: 0 15px 35px rgba(121, 40, 202, 0.3); }
.hero-banner h2 { font-size: 32px; font-weight: 800; margin-bottom: 10px; }
.hero-banner p { font-size: 16px; opacity: 0.9; }

/* Main Responsive Grid Layout */
.main-wrapper { display: grid; grid-template-columns: 1fr; gap: 35px; margin-top: 40px; }
@media(min-width: 992px) { .main-wrapper { grid-template-columns: 2.2fr 1fr; } }

/* Premium Grid News Cards */
.posts-grid { display: grid; grid-template-columns: 1fr; gap: 28px; }
@media(min-width: 600px) { .posts-grid { grid-template-columns: 1fr 1fr; } }

.card { background: var(--light-card); border-radius: var(--radius-prm); overflow: hidden; box-shadow: var(--shadow-prm); transition: var(--transition); border: 1px solid rgba(0,0,0,0.03); display: flex; flex-direction: column; }
.card:hover { transform: translateY(-8px); box-shadow: 0 20px 40px -10px rgba(121, 40, 202, 0.25); }
.card-thumb { height: 230px; background: #e2e8f0; position: relative; overflow: hidden; }
.card-thumb img { width: 100%; height: 100%; object-fit: cover; transition: var(--transition); }
.card:hover .card-thumb img { transform: scale(1.08); }

.badge { position: absolute; top: 15px; left: 15px; background: var(--secondary-gradient); color: #fff; padding: 6px 14px; font-size: 11px; font-weight: 700; border-radius: 8px; text-transform: uppercase; box-shadow: 0 4px 10px rgba(79, 172, 254, 0.3); }
.card-content { padding: 25px; flex-grow: 1; display: flex; flex-direction: column; justify-content: space-between; }
.card-meta { font-size: 12px; color: var(--text-muted); margin-bottom: 12px; display: flex; gap: 15px; font-weight: 500; }
.card-meta i { background: var(--primary-gradient); -webkit-background-clip: text; -webkit-text-fill-color: transparent; }
.card-title { font-size: 20px; font-weight: 700; line-height: 1.4; margin-bottom: 12px; color: var(--text-main); }
.card-title a:hover { background: var(--primary-gradient); -webkit-background-clip: text; -webkit-text-fill-color: transparent; }
.card-text { font-size: 14px; color: var(--text-muted); margin-bottom: 20px; display: -webkit-box; -webkit-line-clamp: 3; -webkit-box-orient: vertical; overflow: hidden; }

/* Read More Gradient Button */
.read-btn { display: inline-flex; align-items: center; gap: 8px; font-weight: 700; font-size: 13px; background: var(--primary-gradient); -webkit-background-clip: text; -webkit-text-fill-color: transparent; width: fit-content; }
.read-btn i { font-size: 11px; transition: var(--transition); -webkit-text-fill-color: initial; color: var(--accent-color); }
.card:hover .read-btn i { transform: translateX(5px); }

/* Sidebar Advanced Widgets */
.sidebar { display: flex; flex-direction: column; gap: 35px; }
.widget { background: var(--light-card); padding: 28px; border-radius: var(--radius-prm); box-shadow: var(--shadow-prm); border: 1px solid rgba(0,0,0,0.02); }
.widget-title { font-size: 16px; font-weight: 800; text-transform: uppercase; margin-bottom: 20px; position: relative; padding-bottom: 10px; letter-spacing: 0.5px; }
.widget-title::after { content: ''; position: absolute; bottom: 0; left: 0; width: 40px; height: 4px; background: var(--primary-gradient); border-radius: 2px; }

/* Footer Section with HadotiEMitra Copyright */
footer { background: #070a12; color: #94a3b8; padding: 70px 0 30px; margin-top: 80px; border-top: 2px solid rgba(121, 40, 202, 0.2); }
.footer-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(240px, 1fr)); gap: 40px; margin-bottom: 50px; }
.footer-col h3 { color: #fff; margin-bottom: 25px; font-size: 20px; font-weight: 700; position: relative; }
.footer-col h3::after { content: ''; position: absolute; bottom: -6px; left: 0; width: 30px; height: 3px; background: var(--secondary-gradient); }
.footer-col p { font-size: 14px; line-height: 1.8; }

/* 100% Locked Copyright Section */
.footer-bottom { border-top: 1px solid rgba(255,255,255,0.08); padding-top: 25px; text-align: center; font-size: 14px; font-weight: 500; color: #64748b; }
.footer-bottom a { background: var(--primary-gradient); -webkit-background-clip: text; -webkit-text-fill-color: transparent; font-weight: 700; }

/* Advanced Back to Top */
#back-to-top { position: fixed; bottom: 30px; right: 30px; background: var(--primary-gradient); color: #fff; width: 46px; height: 46px; border-radius: 50%; display: none; align-items: center; justify-content: center; cursor: pointer; z-index: 999; box-shadow: 0 8px 25px rgba(255, 0, 127, 0.4); border: none; transition: var(--transition); }
#back-to-top:hover { transform: translateY(-5px); }

body.script:
//
// 1. Fluid Dark Mode Transition Engine
const darkToggle = document.getElementById('dark-mode-toggle');
const icon = darkToggle.querySelector('i');
darkToggle.addEventListener('click', () => {
    document.body.classList.toggle('dark-mode');
    if(document.body.classList.contains('dark-mode')) {
        icon.className = 'fas fa-sun';
    } else {
        icon.className = 'fas fa-moon';
    }
});

// 2. Overlay Popup Search Toggle Controller
const searchTrigger = document.getElementById('search-trigger');
const searchLayer = document.getElementById('search-layer');
searchTrigger.addEventListener('click', () => {
    searchLayer.style.display = (searchLayer.style.display === 'flex') ? 'none' : 'flex';
});
window.addEventListener('click', (e) => {
    if(e.target === searchLayer) searchLayer.style.display = 'none';
});

// 3. Dynamic Progress Bar & Responsive Back to Top Logic
window.addEventListener('scroll', () => {
    const winScroll = document.body.scrollTop || document.documentElement.scrollTop;
    const height = document.documentElement.scrollHeight - document.documentElement.clientHeight;
    const scrolled = (winScroll / height) * 100;
    document.getElementById('progress-bar').style.width = scrolled + '%';

    const btt = document.getElementById('back-to-top');
    if(winScroll > 400) { btt.style.display = 'flex'; } else { btt.style.display = 'none'; }
});

document.getElementById('back-to-top').addEventListener('click', () => {
    window.scrollTo({top: 0, behavior: 'smooth'});
});

// 4. Live Automatic Regional Date Engine
document.getElementById('live-date').innerText = new Date().toLocaleDateString('en-US', { weekday: 'short', year: 'numeric', month: 'short', day: 'numeric' });
//
